import ipaddress
import socket
from urllib.parse import urlparse
from django.conf import settings

class UnsafeURLError(ValueError):
    pass

ALLOWED_MECHANIC_HOSTS = getattr(settings, "ALLOWED_MECHANIC_HOSTS", set())

_BLOCKED_NETS = [
    ipaddress.ip_network("127.0.0.0/8"),
    ipaddress.ip_network("10.0.0.0/8"),
    ipaddress.ip_network("172.16.0.0/12"),
    ipaddress.ip_network("192.168.0.0/16"),
    ipaddress.ip_network("169.254.0.0/16"),
    ipaddress.ip_network("::1/128"),
    ipaddress.ip_network("fc00::/7"),
    ipaddress.ip_network("fe80::/10"),
]

def validate_mechanic_url(raw_url: str) -> str:
    parsed = urlparse(raw_url)
    if parsed.scheme not in ("https",):
        raise UnsafeURLError(f"Disallowed scheme: {parsed.scheme}")
    if parsed.username or parsed.password:
        raise UnsafeURLError("Credentials in URL are not allowed")
    host = parsed.hostname
    if not host:
        raise UnsafeURLError("URL has no hostname")
    if host not in ALLOWED_MECHANIC_HOSTS:
        raise UnsafeURLError(f"Host not allowlisted: {host}")
    infos = socket.getaddrinfo(host, None)
    for info in infos:
        ip = ipaddress.ip_address(info[4][0])
        for net in _BLOCKED_NETS:
            if ip in net:
                raise UnsafeURLError(f"Host resolves to private/loopback IP: {ip}")
    return parsed._replace(netloc=host + (f":{parsed.port}" if parsed.port else "")).geturl()

